-- ----------------------------------------------------------------------------
-- SampleDataGovernance: Governance rules for which sample-data rows belong in this rulebook. The Jessica ADVANCED demo is supposed to mirror the worked ABox in the source article — the Production Deployment Workflow at Special Solutions — not a generic catalog of every workflow type. Each row below records one keep/remove decision with a reason and source citation. Used as a checklist when curating seed data; rows here are NOT consumed by substrate code, only by the data-curation process. Originated from LEGACY_PLANs/PLAN-to-cleanup-ADVANCED-table.md (now relocated to this project as PLAN-to-cleanup-ADVANCED-table.md).
-- ----------------------------------------------------------------------------
INSERT INTO sample_data_governance (rule_id, target_table, "action", item_name, reason, source_citation, confidence)
VALUES ('gov-wf-01', 'Workflows', 'keep', 'Production Deployment Workflow', 'The article''s worked ABox names ss:workflow-production-deployment / ''Production Deployment Workflow'' as THE worked workflow instance.', 'Article: explicit naming of the worked workflow.', 'explicit-in-article') ON CONFLICT (rule_id) DO NOTHING;

INSERT INTO sample_data_governance (rule_id, target_table, "action", item_name, reason, source_citation, confidence)
VALUES ('gov-wf-02', 'Workflows', 'remove', 'ALL OTHER (Employee Onboarding, Invoice Approval, Content Publishing, Leave Request, IT Support Ticketing, Expense Reimbursement, Annual Performance Review, Procurement, Customer Feedback, Project Kickoff, Contract Review, Asset Management, Recruitment, Incident Reporting, Change Management)', 'Generic filler from the Airtable export. None of them is the article''s worked workflow.', 'Article worked ABox names exactly one workflow.', 'explicit-in-article') ON CONFLICT (rule_id) DO NOTHING;

