VALUES ('gov-ws-01', 'WorkflowSteps', 'keep', '5 steps of Production Deployment Workflow', 'Article explicitly says the workflow has five steps that produce five named artifacts.', 'Article: five-step count + five-artifact provenance chain.', 'explicit-in-article') ON CONFLICT (rule_id) DO NOTHING;

